use std::collections::HashMap;

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    queries
        .into_iter()
        .map(|query| {
            let l = query[0] as usize;
            let r = query[1] as usize;
            let threshold = query[2] as usize;
            let subarray = &nums[l..=r];

            let mut frequency = HashMap::new();
            for &num in subarray {
                *frequency.entry(num).or_insert(0) += 1;
            }

            let mut candidates: Vec<i64> = frequency
                .iter()
                .filter(|&(_, &count)| count >= threshold)
                .map(|(&num, _)| num)
                .collect();

            if candidates.is_empty() {
                return -1;
            }

            candidates.sort_by(|&a, &b| {
                let freq_a = frequency.get(&a).unwrap();
                let freq_b = frequency.get(&b).unwrap();
                freq_b.cmp(freq_a).then(a.cmp(&b))
            });

            candidates[0]
        })
        .collect()
}
